output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX bd: <http://www.bigdata.com/rdf#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?country ?countryLabel ?hdi ?populationGrowth ?maleSuicideRate ?femaleSuicideRate WHERE {
  ?country wdt:P31 wd:Q6256 .
  ?country wdt:P2586 ?hdi .
  FILTER(isNumeric(?hdi))
  OPTIONAL {
    ?country wdt:P1453 ?populationGrowth .
  }
  OPTIONAL {
    ?country p:P1940 ?maleSuicideStatement .
    ?maleSuicideStatement ps:P1940 ?maleSuicideRate .
    ?maleSuicideStatement pq:P21 wd:Q6581097 .
  }
  OPTIONAL {
    ?country p:P1940 ?femaleSuicideStatement .
    ?femaleSuicideStatement ps:P1940 ?femaleSuicideRate .
    ?femaleSuicideStatement pq:P21 wd:Q6581072 .
  }
  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en" .
  }
}
ORDER BY DESC(?hdi)
LIMIT 10

